function validarFormulario(formId) {
    let valido = true;
    let mensagens = [];

    // percorre os campos obrigatórios
    $(`${formId} .form-validar`).each(function(){
        let input = $(this);
        let valor = input.val().trim();
        let min = input.attr("minlength") || 0;
        let max = input.attr("maxlength") || Infinity;
        let type = input.attr("type") || "text";
        let label = input.closest("label");

        // limpa classes anteriores
        label.removeClass("form-certo form-erros");

        // valida vazio
        if(valor.length < min || valor.length > max || (valor === "")) {
            valido = false;
            mensagens.push(`${input.attr("placeholder") || input.attr("name")} inválido.`);
            label.addClass("form-erros");
            return; // pula para o próximo campo
        }

        // valida email
        if (type === "email") {
            let regexEmail = /^[^\s@]+@[^\s@]+\.[^\s@]+$/;
            if(!regexEmail.test(valor)){
                valido = false;
                mensagens.push("E-mail inválido.");
                label.addClass("form-erros");
                return;
            }
        }

        // se passou em todas validações
        label.addClass("form-certo");
    });

    // mostra mensagem no alerta
    let alerta = $("#form-alerta");
    alerta.removeClass("form-alerta-certo form-alerta-erros");

    if(valido) {
        alerta.text("Formulário validado com sucesso!");
        alerta.addClass("form-alerta-certo").removeClass("display-none");
    } else {
        alerta.text(mensagens.join(" "));
        alerta.addClass("form-alerta-erros").removeClass("display-none");
    }
    
    return valido;
}

// evento do botão salvar
$("#form-button").on("click", function(){
    $("#form-button").prop("disabled", true);
    
    if (validarFormulario(".form-wrap")){
        let id = $("#id").val();
        
        if (id === "" || id === undefined){
            fazerPost();
        } else {
            fazerPut(id);
        }
    }
    else {
        $("#form-button").prop("disabled", false);
    }
});